What does the user see in this component immediately after the page loads, and what do they see after the data arrives?

```jsx
function TeamList() {
  const [teams, setTeams] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('/api/teams')
      .then(res => res.json())
      .then(data => {
        setTeams(data);
        setLoading(false);
      });
  }, []);

  if (loading) return <p>Loading teams...</p>;

  return (
    <ul>
      {teams.map(team => (
        <li key={team.id}>{team.name}</li>
      ))}
    </ul>
  );
}
```

The client says: "Every time I switch between departments, the old department's employees show for a split second before the new ones load." What is missing from this component?

```jsx
function EmployeeList({ departmentId }) {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`/api/departments/${departmentId}/employees`)
      .then(res => res.json())
      .then(data => {
        setEmployees(data);
        setLoading(false);
      });
  }, [departmentId]);

  if (loading) return <Spinner />;

  return (
    <ul>
      {employees.map(emp => (
        <li key={emp.id}>{emp.name}</li>
      ))}
    </ul>
  );
}
```

You are reviewing AI-generated code for a dashboard. The client says the page is blank -- no data, no spinner, no error message. What are the problems?

```jsx
function Dashboard() {
  const [metrics, setMetrics] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    async function load() {
      const res = await fetch('/api/metrics');
      const data = await res.json();
      setMetrics(data);
      setLoading(false);
    }
    load();
  }, []);

  if (loading) return <Spinner />;
  if (!metrics) return null;

  return (
    <div>
      <h1>Dashboard</h1>
      <p>Revenue: ${metrics.revenue}</p>
      <p>Users: {metrics.users}</p>
    </div>
  );
}
```
